import React from "react";
import { motion } from "framer-motion";
import DarkModeToggle from "./components/DarkModeToggle";

function App() {
  return (
    <div className="bg-white dark:bg-gray-900 text-black dark:text-white min-h-screen">
      {/* Navbar */}
      <nav className="p-4 flex justify-between items-center border-b border-gray-300 dark:border-gray-700">
        <h1 className="text-2xl font-bold">My Portfolio</h1>
        <DarkModeToggle />
      </nav>

      {/* Hero Section with Animation */}
      <main className="p-6 flex flex-col items-center text-center">
        <motion.h2
          className="text-4xl font-bold"
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 1 }}
        >
          Welcome to My Portfolio
        </motion.h2>
        <motion.p
          className="mt-2 text-lg"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.5, duration: 1 }}
        >
          I build awesome web applications using React.
        </motion.p>
      </main>

      {/* Footer */}
      <footer className="p-4 text-center border-t border-gray-300 dark:border-gray-700">
        © 2025 Ritesh Chakramani. All rights reserved.
      </footer>
    </div>
  );
}

export default App;
